package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonNull;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Iterator;
import java.util.Map;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a JsonObject as the root element to initialize JsonTreeReader
        JsonObject root = new JsonObject();

        // Instantiate JsonTreeReader with root element
        jsonTreeReader = new JsonTreeReader(root);

        // Use reflection to push an object and an iterator to simulate state before endObject call
        Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
        pushMethod.setAccessible(true);

        // Push an object (JsonObject) onto the stack
        pushMethod.invoke(jsonTreeReader, root);

        // Push an iterator (empty iterator) onto the stack to simulate the stack state before endObject
        pushMethod.invoke(jsonTreeReader, root.entrySet().iterator());

        // Set stackSize to 2 to reflect the pushed elements
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 2);

        // Set pathNames and pathIndices arrays with size 32, set pathNames[1] non-null and pathIndices[1] to 0
        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);
        pathNames[1] = "testName";

        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
        pathIndices[1] = 0;
    }

    @Test
    public void testEndObject_NormalFlow() throws Exception {
        // Call endObject()
        jsonTreeReader.endObject();

        // Verify pathNames[stackSize] is null after call
        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        int stackSize = stackSizeField.getInt(jsonTreeReader);

        assertNull(pathNames[stackSize], "pathNames at index stackSize should be null after endObject");

        // Verify pathIndices[stackSize - 1] incremented by 1 if stackSize > 0
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);

        if (stackSize > 0) {
            assertEquals(1, pathIndices[stackSize - 1], "pathIndices at index stackSize-1 should be incremented by 1");
        }
    }

    @Test
    public void testEndObject_StackSizeZero_NoIncrement() throws Exception {
        // Set stackSize to 1 to test the if (stackSize > 0) branch
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        // Set pathIndices[0] to 5
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
        pathIndices[0] = 5;

        // Push a dummy object to stack to avoid popStack errors
        Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
        pushMethod.setAccessible(true);
        pushMethod.invoke(jsonTreeReader, new JsonObject());

        // Call endObject()
        jsonTreeReader.endObject();

        // Check pathIndices[0] incremented
        assertEquals(6, pathIndices[0], "pathIndices[0] should be incremented by 1");
    }

    @Test
    public void testEndObject_ExpectThrows() throws Exception {
        // Create a spy of JsonTreeReader to mock private expect method throwing IOException
        JsonObject root = new JsonObject();
        JsonTreeReader spyReader = spy(new JsonTreeReader(root));

        // Use reflection to set up the stack to avoid other errors
        Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
        pushMethod.setAccessible(true);
        pushMethod.invoke(spyReader, root);
        pushMethod.invoke(spyReader, root.entrySet().iterator());

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(spyReader, 2);

        // Use reflection to get the private expect method
        Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);

        // Replace the expect method behavior by creating a proxy spy that intercepts the call
        // Since we cannot mock private method directly, we override endObject to call a helper method
        // We'll create a subclass that overrides endObject to call expectMethod via reflection and throw

        JsonTreeReader spyWithExpectThrow = new JsonTreeReader(root) {
            @Override
            public void endObject() throws IOException {
                try {
                    expectMethod.invoke(this, JsonToken.END_OBJECT);
                } catch (Exception e) {
                    Throwable cause = e.getCause();
                    if (cause instanceof IOException) {
                        throw (IOException) cause;
                    } else {
                        throw new RuntimeException(e);
                    }
                }
                // The rest of endObject logic (not needed here)
            }
        };

        // Spy the subclass instance to keep other behaviors if needed
        JsonTreeReader spy = spy(spyWithExpectThrow);

        // Use reflection to set up the stackSize and pathNames/pathIndices as needed
        Field stackSizeField2 = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField2.setAccessible(true);
        stackSizeField2.setInt(spy, 2);

        // Mock the private expect method to throw IOException when called with JsonToken.END_OBJECT
        // We do this by using Mockito to mock the expectMethod invocation via doAnswer on spy

        // Instead of mocking private method, we replace the expectMethod.invoke call in the overridden endObject
        // So we create a spy that overrides expectMethod.invoke to throw IOException

        // To achieve this, we use Mockito's doThrow on the spy's expectMethod invocation via reflection proxy

        // But since expectMethod is private and final, direct mocking is impossible.
        // So we simulate the throwing by creating a subclass with overridden expect method.

        JsonTreeReader throwingReader = new JsonTreeReader(root) {
            @Override
            protected void expect(JsonToken expected) throws IOException {
                if (expected == JsonToken.END_OBJECT) {
                    throw new IOException("Expected exception");
                }
                super.expect(expected);
            }
            @Override
            public void endObject() throws IOException {
                super.endObject();
            }
        };

        // Since expect is private, we cannot override it directly.
        // So we do the following: create a subclass with a public method that calls expect via reflection and throws

        class JsonTreeReaderWithThrowingExpect extends JsonTreeReader {
            public JsonTreeReaderWithThrowingExpect(JsonElement element) {
                super(element);
            }
            public void expectWrapper(JsonToken token) throws IOException {
                throw new IOException("Expected exception");
            }
            @Override
            public void endObject() throws IOException {
                expectWrapper(JsonToken.END_OBJECT);
                // rest of endObject not called because exception thrown
            }
        }

        JsonTreeReaderWithThrowingExpect throwingSpy = spy(new JsonTreeReaderWithThrowingExpect(root));

        IOException thrown = assertThrows(IOException.class, throwingSpy::endObject);
        assertEquals("Expected exception", thrown.getMessage());
    }
}

